const now = new Date();
const fmt = new Intl.DateTimeFormat('en-US', { timeZone: 'Europe/Madrid', hour: 'numeric', hour12: false, weekday: 'short' });
const parts = fmt.formatToParts(now);
const madridHour = parseInt(parts.find(p => p.type === 'hour').value);
const dayName = parts.find(p => p.type === 'weekday').value;
const weekdays = ['Mon','Tue','Wed','Thu','Fri'];
const isWeekday = weekdays.includes(dayName);
const isValid = isWeekday && madridHour >= 8 && madridHour < 19;
return [{ json: { isValid, madridHour, dayName } }];

const MAX_PER_CYCLE = 7;
const records = $input.first().json.records || [];
const results = [];
for (const rec of records) {
  const f = rec.fields || {};
  if ((f.Pipeline || '') !== '✅ Aprobado') continue;
  const empresaIds = f['Empresa link'] || [];
  const empresaId = empresaIds[0] || '';
  if (!empresaId) continue;
  results.push({ json: {
    recordId: rec.id,
    empresaId,
    asunto: f.Asunto || '',
    email1Body: f['Email 1 Body'] || '',
    slug: f.Slug || '',
    action: 'send_email_1'
  }});
}
return results.slice(0, MAX_PER_CYCLE);

const allPrev = $('Procesar Secuencias').all();
const allInput = $input.all();
const today = new Date(); today.setHours(0,0,0,0);
const firma = '<table cellpadding="0" cellspacing="0" border="0" style="background:none;border:0;margin:0;padding:0;background-color:#FFFFFF;padding-top:20px"><tbody><tr><td valign="top" style="width:190px;padding:0 7px 0 0;border-right:solid 3px #5DFFBF"><img src="https://trespuntoscomunicacion.es/img_firma/new-logo.jpg"></td><td style="padding:0 0 0 12px"><table cellpadding="0" cellspacing="0" border="0" style="background:none;border:0;margin:0;padding:0"><tbody><tr><td colspan="2" style="padding-bottom:5px;color:#5DFFBF;font-size:18px;font-weight:800;font-family:Oswald,Helvetica,sans-serif">Tres Puntos | Agencia diseno web UX/UI</td></tr><tr><td colspan="2" style="padding-bottom:5px;color:#2A2A2A;font-size:16px;font-family:Oswald,Helvetica,sans-serif">Jordi Exposito | Founder &amp; Digital Experience Manager</td></tr><tr><td colspan="2" style="padding-bottom:5px;color:#2A2A2A;font-size:16px;font-family:Oswald,Helvetica,sans-serif">Email: <a href="mailto:jordi@trespuntoscomunicacion.es" style="color:#5DFFBF;text-decoration:none;font-size:16px">jordi@trespuntoscomunicacion.es</a></td></tr><tr><td colspan="2" style="padding-bottom:5px;color:#2A2A2A;font-size:16px;font-family:Oswald,Helvetica,sans-serif">Web: <a href="https://www.trespuntoscomunicacion.es" style="color:#5DFFBF;text-decoration:none;font-size:16px">www.trespuntoscomunicacion.es</a></td></tr><tr><td colspan="2" style="padding-bottom:5px;color:#2A2A2A;font-size:16px;font-family:Oswald,Helvetica,sans-serif">Telefono: <a href="tel://654057176" style="color:#2A2A2A;text-decoration:none;font-size:16px">654 057 176</a></td></tr><tr><td colspan="2" style="padding-bottom:5px;color:#2A2A2A;font-size:16px;font-family:Oswald,Helvetica,sans-serif">Nos reunimos? <a href="https://calendly.com/trespuntos/tres-puntos" style="color:#5DFFBF;text-decoration:none">Reserva cita ahora</a></td></tr></tbody></table></td></tr></tbody></table>';
const results = [];
for (let i = 0; i < allInput.length; i++) {
  const prev = allPrev[i]?.json || allPrev[0]?.json || {};
  const empresa = allInput[i].json.fields || {};
  const estado = empresa.Estado || '';
  const prioridad = empresa.Prioridad || '';
  const fechaProx = empresa['Fecha próxima acción'] ? new Date(empresa['Fecha próxima acción']) : null;
  if (estado !== 'Prospecto') continue;
  if (prioridad !== 'A') continue;
  if (fechaProx && fechaProx > today) continue;
  const slug = prev.slug || empresa.Slug || '';
  results.push({ json: {
    ...prev,
    toEmail: empresa.Email || '',
    decisor: empresa['Contacto nombre'] || '',
    empresaNombre: empresa.Nombre || '',
    sector: empresa.Sector || '',
    empresaRecordId: allInput[i].json.id || prev.empresaId || '',
    slug,
    firma
  }});
}
return results;

return $input.all().map(item => {
  const d = item.json;
  const trackUrl = 'https://go.trespuntoscomunicacion.es/s/' + (d.slug || '') + '?e=1';
  let body = (d.email1Body || '').toString();
  body = body.replace(/https?:\/\/(?:www\.)?trespuntoscomunicacion\.es\/sectores\/analisis\/[a-z0-9-]+\/?/gi, trackUrl);
  body = body.replace(/https?:\/\/go\.trespuntoscomunicacion\.es\/s\/[a-z0-9-]+\/?(\?[^\s]*)?/gi, trackUrl);
  body = body.replace(/\[([^\]]+)\]\((https?:\/\/[^\)]+trespuntoscomunicacion\.es\/sectores[^\)]*)\)/gi, '<a href="' + trackUrl + '">$1</a>');
  const paragraphs = body.split(/\n\s*\n/).map(p => '<p style="margin:0 0 14px 0;">' + p.replace(/\n/g, '<br>') + '</p>').join('');
  const customMsgId = '<' + d.recordId + '-e1-sectores@trespuntos-lab.com>';
  const htmlBody = '<div style="font-family:Arial,sans-serif;font-size:14px;color:#2A2A2A;line-height:1.6">' + paragraphs + '<br>' + d.firma + '</div>';
  const subject = d.asunto || '';
  const mimeLines = [
    'From: =?UTF-8?B?' + Buffer.from('Jordi Exposito').toString('base64') + '?= <jordi@trespuntoscomunicacion.es>',
    'Reply-To: jordi@trespuntoscomunicacion.es',
    'To: ' + d.toEmail,
    'Subject: =?UTF-8?B?' + Buffer.from(subject).toString('base64') + '?=',
    'Message-ID: ' + customMsgId,
    'MIME-Version: 1.0',
    'Content-Type: text/html; charset=UTF-8',
    '',
    htmlBody
  ];
  const mime = mimeLines.join('\r\n');
  const raw = Buffer.from(mime).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
  return { json: { ...d, raw, customMsgId, trackUrl } };
});

